<template>
    <!-- 모달을 트리거할 버튼 -->
    <button type="button" class="btn btn-primary" @click="openModal">
      병원 정보
    </button>
  
    <!-- 모달 컴포넌트 -->
    <div class="modal fade" id="exampleModal" tabindex="-1" aria-labelledby="exampleModalLabel" aria-hidden="true" ref="modalRef">
      <div class="modal-dialog">
        <div class="modal-content">
          <div class="modal-header">
            <h5 class="modal-title" id="exampleModalLabel">상세 페이지</h5>
            <button type="button" class="btn-close" data-bs-dismiss="modal" aria-label="Close"></button>
          </div>
          <div class="modal-body">
            <h4>{{ 게시글[$route.params.id]?.title }}</h4>
            <h5>{{ 게시글[$route.params.id]?.content }}</h5>
            <h6>{{ 게시글[$route.params.id]?.date }}</h6>
          </div>
          <div class="modal-footer">
            <button type="button" class="btn btn-secondary" data-bs-dismiss="modal">Close</button>
            <button type="button" class="btn btn-primary">Save changes</button>
          </div>
        </div>
      </div>
    </div>
  </template>
  
  <script>
  import { ref, onMounted } from 'vue'
  import { Modal } from 'bootstrap'
  
  export default {
    props: {
      게시글: Array,
    },
    setup() {
      const modalRef = ref(null)
      let myModal = null
  
      onMounted(() => {
        myModal = new Modal(modalRef.value)
      })
  
      const openModal = () => {
        if (myModal) {
          myModal.show()
        }
      }
  
      return {
        modalRef,
        openModal
      }
    }
  }
  </script>